import { useEffect, useState } from "react"
import API from "../services/api"

export default function Jobs() {

    const [job, setJob] = useState(null)
    const [strengths,setStrengths]= useState([])
    const [missingSkills,setMissingSKills]=useState([])
    const [predictions,setPredictions]=useState([])
    const [roadmap,setRoadmap]=useState([])

    useEffect(() => {

        const fetchRecommendation = async () => {

            try {

                const token = localStorage.getItem("token")

                const res = await API.get(
                    "/jobs/recommend",
                    {
                        headers: {
                            Authorization: `Bearer ${token}`
                        }
                    }
                )

                setJob(res.data)
                setStrengths(res.data.strengths || [])
                setMissingSKills(res.data.missingSKills || [])
                setPredictions(res.data.topPredictions || [])
                setRoadmap(res.data.roadmap || [])

            } catch (error) {

                console.log(error)
            }
        }

        fetchRecommendation()

    }, [])

    const handleSaveJob = async () => {

        try {

            const token = localStorage.getItem("token")

            await API.post(
                "/jobs/save",
                {
                    role: job.recommendedRole
                },
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            )

            alert("Job saved!")

        } catch (error) {

            console.log(error)
        }
    }

    return (

        <div
            style={{
                padding: "30px",
                background: "#f4f4f4",
                minHeight: "100vh"
            }}
        >

            <h1
                style={{
                    marginBottom: "25px",
                    color: "#222"
                }}
            >
                Recommended Career Role
            </h1>

            {
                job ? (

                    <div
                        style={{
                            background: "white",
                            borderRadius: "15px",
                            padding: "25px",
                            maxWidth: "500px",
                            boxShadow:
                                "0 4px 12px rgba(0,0,0,0.1)"
                        }}
                    >

            <h2
                style={{
                    color: "#4CAF50",
                    marginBottom: "15px"
                }}
            >
                {job.recommendedRole}
            </h2>

            <h3>Top Career Matches</h3>

            {
                predictions.map((item, index) => (

                    <div
                        key={index}

                        style={{
                            marginBottom: "15px"
                        }}
                    >

                        <p>
                            <strong>
                                {item.role}
                            </strong>
                        </p>

                        <div
                            style={{
                                background: "#ddd",
                                borderRadius: "10px",
                                overflow: "hidden",
                                height: "20px"
                            }}
                        >

                            <div
                                style={{
                                    width: `${item.confidence * 5}%`,
                                    background: "#4CAF50",
                                    height: "100%"
                                }}
                            />

                        </div>

                        <p>
                            {item.confidence.toFixed(2)}%
                        </p>

                    </div>
                ))
            }
                    <h3>Your Strengths</h3>
                    <ul>
                        {
                            strengths.map((skill, index) => (
                                <li key={index}>
                                    {skill}
                                </li>
                            ))
                        }
                    </ul>
                    <h3>Skills To Improve</h3>
                    <ul>
                        {
                            missingSkills.map((skill, index) => (
                                <li key={index}>
                                    {skill}
                                </li>
                            ))
                        }
                    </ul>
                    <hr style={{ margin: "25px 0" }} />

                    <h3>Personalized Learning Roadmap</h3>
                    <div>
                        {
                            roadmap.map((step, index) => (
                                <div
                                    key={index}
                                    style={{
                                        display: "flex",
                                        alignItems: "center",
                                        marginBottom: "15px",
                                        background: "#f9f9f9",
                                        padding: "12px",
                                        borderRadius: "10px"
                                    }}
                                >
                                    <div
                                        style={{
                                            width: "35px",
                                            height: "35px",
                                            borderRadius: "50%",
                                            background: "#4CAF50",
                                            color: "white",
                                            display: "flex",
                                            alignItems: "center",
                                            justifyContent: "center",
                                            marginRight: "15px",
                                            fontWeight: "bold"
                                        }}
                                    >
                                        {index + 1}
                                    </div>
                                    <p
                                        style={{
                                            margin: 0
                                        }}
                                    >
                                        {step}
                                    </p>

                                </div>
                            ))
                        }

                    </div>
                        <p
                            style={{
                                fontSize: "18px"
                            }}
                        >
                            <strong>Match Score:</strong>{" "}
                            {job.matchScore}
                        </p>

                        <button
                            onClick={handleSaveJob}
                            style={{
                                marginTop: "20px",
                                padding: "10px 18px",
                                border: "none",
                                backgroundColor: "#4CAF50",
                                color: "white",
                                borderRadius: "8px",
                                cursor: "pointer",
                                fontSize: "15px"
                            }}
                        >
                            Save Job
                        </button>

                    </div>

                ) : (

                    <p>Loading recommendation...</p>

                )
            }

        </div>
    )
}
